// Wire types shared with the Rust backend are generated by `ts-rs` from
// `crates/belisarius-core/src/lib.rs`. Re-run `cargo test -p belisarius-core
// --features ts` after editing those structs; the output lands in
// `web/src/types/generated/` (checked in).
//
// Shapes below that are NOT generated are server-side composites (response
// wrappers like `Brief`, `FunctionDetail`, `QualitySummary`) — these will
// migrate to `ts-rs` next as their service modules are annotated.
import type {
  AnalysisReport,
  Brief,
  CallersResponse,
  Diagnostic,
  DiagnosticsReport,
  EdgeKind,
  FileMetrics,
  FileNode,
  FlowReport,
  FunctionDetail,
  FunctionInfo,
  FunctionsResponse,
  Graph,
  GraphCycle,
  GraphEdge,
  GraphNode,
  ImpactReport,
  ImportEdge,
  LanguageSummary,
  MarkerHit,
  MarkersResponse,
  Quality,
  QualityAxes,
  QualityIssue,
  QualityResponse,
  Range,
  RefsResponse,
  Scan,
  Severity,
  SnippetResponse,
  SurfaceItem,
  SurfaceKind,
  SurfaceReport,
  Symbol360,
  SymbolMatch,
  SymbolOccurrence,
  SymbolsSearchResponse,
  SymbolsStatusResponse,
  ToolStatus,
} from "./types/generated";

