// Back-compat aliases — older callers still reference these names.
//   QualitySummary  ← QualityResponse
//   Snippet         ← SnippetResponse (the project endpoint; the generated
//                     `Snippet` is the smaller function_detail-nested type)
//   SymbolStatus    ← SymbolsStatusResponse
//   SymbolRef       ← SymbolOccurrence (refs/call_sites array elements)
export type QualitySummary = QualityResponse;
export type Snippet = SnippetResponse;
export type SymbolStatus = SymbolsStatusResponse;
export type SymbolRef = SymbolOccurrence;

