async function call<T>(
  path: string,
  init?: RequestInit,
  signal?: AbortSignal,
): Promise<T> {
  const resp = await fetch(path, {
    ...init,
    signal: signal ?? init?.signal,
    headers: { 'content-type': 'application/json', ...(init?.headers ?? {}) },
  });
  if (!resp.ok) {
    let detail = await resp.text();
    try {
      const j = JSON.parse(detail);
      if (j?.error) detail = j.error;
    } catch {
      /* ignore */
    }
    throw new Error(`HTTP ${resp.status}: ${detail}`);
  }
  return (await resp.json()) as T;
}

// Every method in `api` accepts an optional trailing `signal?: AbortSignal`.
// When passed (always passed from `queries.ts` via react-query's
// `QueryFunctionContext`), it propagates to `fetch` so unmounting a
// component or rapid path changes abort the in-flight request at the
// network layer — not just at the framework layer.
export const api = {
  scan: (path?: string, signal?: AbortSignal) =>
    call<Scan>(
      `/api/scan${path ? `?path=${encodeURIComponent(path)}` : ''}`,
      { method: 'POST' },
      signal,
    ),
  graph: (path?: string, signal?: AbortSignal) =>
    call<Graph>(
      `/api/graph${path ? `?path=${encodeURIComponent(path)}` : ''}`,
      { method: 'POST' },
      signal,
    ),
  symbolsStatus: (path: string, signal?: AbortSignal) =>
    call<SymbolStatus>(
      `/api/symbols/status?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  symbolsSearch: (path: string, q: string, limit = 30, signal?: AbortSignal) =>
    call<{ matches: SymbolMatch[] }>(
      `/api/symbols/search?path=${encodeURIComponent(path)}&q=${encodeURIComponent(q)}&limit=${limit}`,
      undefined,
      signal,
    ).then((r) => r.matches),
  symbolsRefs: (path: string, sym: string, signal?: AbortSignal) =>
    call<RefsResponse>(
      `/api/symbols/refs?path=${encodeURIComponent(path)}&sym=${encodeURIComponent(sym)}`,
      undefined,
      signal,
    ),
  symbolsCallers: (path: string, sym: string, signal?: AbortSignal) =>
    call<CallersResponse>(
      `/api/symbols/callers?path=${encodeURIComponent(path)}&sym=${encodeURIComponent(sym)}`,
      undefined,
      signal,
    ),
  quality: (path: string, signal?: AbortSignal) =>
    call<QualitySummary>(
      `/api/quality?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  brief: (path: string, signal?: AbortSignal) =>
    call<Brief>(`/api/brief?path=${encodeURIComponent(path)}`, undefined, signal),
  functionDetail: (path: string, file: string, name: string, signal?: AbortSignal) =>
    call<FunctionDetail>(
      `/api/function?path=${encodeURIComponent(path)}&file=${encodeURIComponent(file)}&name=${encodeURIComponent(name)}`,
      undefined,
      signal,
    ),
  functions: (
    path: string,
    opts: { minCc?: number; limit?: number; sortBy?: string; file?: string } = {},
    signal?: AbortSignal,
  ) => {
    const parts = [`path=${encodeURIComponent(path)}`];
    if (opts.minCc !== undefined) parts.push(`min_cc=${opts.minCc}`);
    if (opts.limit !== undefined) parts.push(`limit=${opts.limit}`);
    if (opts.sortBy) parts.push(`sort_by=${encodeURIComponent(opts.sortBy)}`);
    if (opts.file) parts.push(`file=${encodeURIComponent(opts.file)}`);
    return call<FunctionsResponse>(`/api/functions?${parts.join('&')}`, undefined, signal);
  },
  snippet: (path: string, file: string, line: number, radius = 25, signal?: AbortSignal) =>
    call<Snippet>(
      `/api/snippet?path=${encodeURIComponent(path)}&file=${encodeURIComponent(file)}&line=${line}&radius=${radius}`,
      undefined,
      signal,
    ),
  markers: (path: string, limit = 500, signal?: AbortSignal) =>
    call<MarkersResponse>(
      `/api/markers?path=${encodeURIComponent(path)}&limit=${limit}`,
      undefined,
      signal,
    ),
  fileDsm: (path: string, file: string, signal?: AbortSignal) =>
    call<FileDsm>(
      `/api/file_dsm?path=${encodeURIComponent(path)}&file=${encodeURIComponent(file)}`,
      undefined,
      signal,
    ),
  diagnosticsStatus: (path: string, signal?: AbortSignal) =>
    call<{ tools: DiagToolStatus[] }>(
      `/api/diagnostics/status?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  diagnosticsRun: (path: string, tools?: string[], force = false, signal?: AbortSignal) =>
    call<{ cached: boolean; report: DiagnosticsReport }>(
      '/api/diagnostics/run',
      {
        method: 'POST',
        body: JSON.stringify({ path, tools, force }),
      },
      signal,
    ),
  diagnosticsList: (
    path: string,
    opts: { tool?: string; severity?: string; file?: string; limit?: number } = {},
    signal?: AbortSignal,
  ) => {
    const parts = [`path=${encodeURIComponent(path)}`];
    if (opts.tool) parts.push(`tool=${encodeURIComponent(opts.tool)}`);
    if (opts.severity) parts.push(`severity=${encodeURIComponent(opts.severity)}`);
    if (opts.file) parts.push(`file=${encodeURIComponent(opts.file)}`);
    if (opts.limit) parts.push(`limit=${opts.limit}`);
    return call<{
      total_cached: number;
      returned: number;
      diagnostics: Diagnostic[];
      counts_by_tool: Record<string, number>;
      counts_by_severity: Record<string, number>;
      tools_ran: ToolStatus[];
    }>(`/api/diagnostics?${parts.join('&')}`, undefined, signal);
  },
  architectureMermaid: (
    path: string,
    opts: { view?: 'module' | 'file'; maxNodes?: number; groupDepth?: number } = {},
    signal?: AbortSignal,
  ) => {
    const parts = [`path=${encodeURIComponent(path)}`];
    parts.push(`view=${opts.view ?? 'module'}`);
    parts.push(`max_nodes=${opts.maxNodes ?? 60}`);
    parts.push(`group_depth=${opts.groupDepth ?? 2}`);
    return call<ArchitectureMermaid>(
      `/api/architecture/mermaid?${parts.join('&')}`,
      undefined,
      signal,
    );
  },
  architectureGraph: (
    path: string,
    opts: { view?: 'module' | 'file'; maxNodes?: number; groupDepth?: number } = {},
    signal?: AbortSignal,
  ) => {
    const parts = [`path=${encodeURIComponent(path)}`];
    parts.push(`view=${opts.view ?? 'module'}`);
    parts.push(`max_nodes=${opts.maxNodes ?? 60}`);
    parts.push(`group_depth=${opts.groupDepth ?? 2}`);
    return call<ArchitectureGraph>(
      `/api/architecture/graph?${parts.join('&')}`,
      undefined,
      signal,
    );
  },
  components: (path: string, signal?: AbortSignal) =>
    call<ComponentsResponse>(
      `/api/components?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  architectureModule: (path: string, module: string, groupDepth = 2, signal?: AbortSignal) =>
    call<ArchitectureModule>(
      `/api/architecture/module?path=${encodeURIComponent(path)}&module=${encodeURIComponent(module)}&group_depth=${groupDepth}`,
      undefined,
      signal,
    ),
  hotspots: (path: string, days = 90, limit = 40, signal?: AbortSignal) =>
    call<HotspotsResponse>(
      `/api/hotspots?path=${encodeURIComponent(path)}&days=${days}&limit=${limit}`,
      undefined,
      signal,
    ),
  testGaps: (path: string, limit = 50, signal?: AbortSignal) =>
    call<TestMap>(
      `/api/test_gaps?path=${encodeURIComponent(path)}&limit=${limit}`,
      undefined,
      signal,
    ),
  commands: (path: string, signal?: AbortSignal) =>
    call<WorkspaceCommands>(
      `/api/commands?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  surface: (path: string, signal?: AbortSignal) =>
    call<SurfaceReport>(
      `/api/surface?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),

  // ── Fleet ─────────────────────────────────────────────────────────────
  fleetList: () => call<FleetListResponse>('/api/fleet'),
  fleetFind: (pattern: string, opts: { kind?: string; limit?: number } = {}) => {
    const parts = [`pattern=${encodeURIComponent(pattern)}`];
    if (opts.kind) parts.push(`kind=${encodeURIComponent(opts.kind)}`);
    if (opts.limit != null) parts.push(`limit=${opts.limit}`);
    return call<FleetFindResponse>(`/api/fleet/find?${parts.join('&')}`);
  },
  fleetHotspots: (limit = 25) =>
    call<FleetHotspotsResponse>(`/api/fleet/hotspots?limit=${limit}`),
  fleetTestGaps: (limit = 25) =>
    call<FleetTestGapsResponse>(`/api/fleet/test_gaps?limit=${limit}`),
  fleetDiff: (from: string, to: string) =>
    call<FleetDiffResponse>(
      `/api/fleet/surface_diff?from=${encodeURIComponent(from)}&to=${encodeURIComponent(to)}`,
    ),

  // ── Hybrid semantic + BM25 search ─────────────────────────────────────
  searchCode: (
    path: string,
    q: string,
    opts: { limit?: number; lang?: string; kind?: string } = {},
  ) => {
    const parts = [`path=${encodeURIComponent(path)}`, `q=${encodeURIComponent(q)}`];
    if (opts.limit != null) parts.push(`limit=${opts.limit}`);
    if (opts.lang) parts.push(`lang=${encodeURIComponent(opts.lang)}`);
    if (opts.kind) parts.push(`kind=${encodeURIComponent(opts.kind)}`);
    return call<SearchResponse>(`/api/search?${parts.join('&')}`);
  },
  searchStatus: (path: string, signal?: AbortSignal) =>
    call<IndexStatus>(
      `/api/search/status?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  searchReindex: (path: string, opts: { full?: boolean; bm25Only?: boolean } = {}) => {
    const parts = [`path=${encodeURIComponent(path)}`];
    if (opts.full) parts.push('full=true');
    if (opts.bm25Only) parts.push('bm25_only=true');
    return call<IndexStatus>(`/api/search/reindex?${parts.join('&')}`, { method: 'POST' });
  },

  // ── Transitive xref ────────────────────────────────────────────────────
  impact: (path: string, sym: string, depth = 3, signal?: AbortSignal) =>
    call<ImpactReport>(
      `/api/impact?path=${encodeURIComponent(path)}&sym=${encodeURIComponent(sym)}&depth=${depth}`,
      undefined,
      signal,
    ),
  flow: (path: string, sym: string, depth = 3, signal?: AbortSignal) =>
    call<FlowReport>(
      `/api/flow?path=${encodeURIComponent(path)}&sym=${encodeURIComponent(sym)}&depth=${depth}`,
      undefined,
      signal,
    ),
  symbol360: (path: string, sym: string, signal?: AbortSignal) =>
    call<Symbol360>(
      `/api/symbol?path=${encodeURIComponent(path)}&sym=${encodeURIComponent(sym)}`,
      undefined,
      signal,
    ),

  // ── Context artifacts ─────────────────────────────────────────────────
  contextList: (path: string, signal?: AbortSignal) =>
    call<ContextListResponse>(
      `/api/context?path=${encodeURIComponent(path)}`,
      undefined,
      signal,
    ),
  contextGet: (path: string, name: string, signal?: AbortSignal) =>
    call<ContextArtifactContent>(
      `/api/context/get?path=${encodeURIComponent(path)}&name=${encodeURIComponent(name)}`,
      undefined,
      signal,
    ),
  contextSearch: (path: string, q: string, limit = 10) =>
    call<SearchResponse>(
      `/api/context/search?path=${encodeURIComponent(path)}&q=${encodeURIComponent(q)}&limit=${limit}`,
    ),
  contextIndex: (path: string) =>
    call<{ indexed_chunks: number }>(`/api/context/index?path=${encodeURIComponent(path)}`, {
      method: 'POST',
    }),
};
